        int m = s2.length();
        int k = s3.length();

        int dp[n + 1][m + 1][k + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                for (int k = 0; k <= k; k++) {
                    dp[i][j][k] = INT_MAX;
